import Button from '@mui/material/Button';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';

import { styled } from '@mui/material/styles';
import { useNavigate } from 'react-router-dom';

const Icon = styled(ArrowForwardIcon)(() => ({
  // backgroundColor: 'grey',
  position: 'relative',
  top: '7px',
  backgroundSize: '10px',
}))

const ButtonArrow = styled(Button)(() => ({
	minWidth: '0px',
	padding: '0px',
  margin: '0px 0px',
  border: 'none',
  background: 'none',
  position: 'relative',
  display: 'flex',
  fontWeight: 400,
  fontSize: '14px',
  gap: '0.5rem',
  alignItems: 'center',

	// 'p': {
	// 	margin: 0,
	// 	position: 'relative',
	// 	color: '#32292F', // color: '#fff',
	// },

	// '&::after': {
	// 	position: 'absolute',
	// 	content: '""',
	// 	width: 0,
	// 	left: 0,
	// 	bottom: '-7px',
	// 	background: '#6E7DAB', // background: '#fff',
	// 	height: '2px',
	// 	transition: '0.3s ease-out',
	// },

	'&:hover': {
		background: 'none',
	},

	// '&:hover p': {
	// 	color: '#6E7DAB',
	// 	transition: '0.5s ease-in-out',
	// },

	'&:hover::after': {
		width: '100%',
	},
}))

const ButtonArrowWhite = styled(ButtonArrow)(() => ({
  'p': {
		margin: 0,
		position: 'relative',
		color: '#fff',
	},
  '&::after': {
		position: 'absolute',
		content: '""',
		width: 0,
		left: 0,
		bottom: '-7px',
		background: '#fff',
		height: '2px',
		transition: '0.3s ease-out',
	},
  '&:hover p': {
		color: '#fff',
		transition: '0.5s ease-in-out',
	},
}));

const ButtonArrowDark = styled(ButtonArrow)(() => ({
  'p': {
		margin: 0,
		position: 'relative',
		color: '#32292F',
	},

	'&::after': {
		position: 'absolute',
		content: '""',
		width: 0,
		left: 0,
		bottom: '-7px',
		background: '#6E7DAB',
		height: '2px',
		transition: '0.3s ease-out',
	},
  '&:hover p': {
		color: '#6E7DAB',
		transition: '0.5s ease-in-out',
	},
}));

function NavButton({ link, text, setActiveLink, colour, arrow, customStyle }) {
  const navigate = useNavigate();

	console.log('link', link);

	const handleClick = () => {
		setActiveLink(link);
		navigate('/' + link);
	}

  return (
    <>
      {
        colour === 'white' && arrow ?
        <ButtonArrowWhite onClick={() => handleClick()} disableRipple={true}>
          <p>{text} <Icon viewBox='0 0 18 24'/></p>
        </ButtonArrowWhite> :
				colour === 'white' && !arrow ?
				<ButtonArrowWhite onClick={() => handleClick()} disableRipple={true}>
					<p>{text} </p>
				</ButtonArrowWhite> :
				colour === 'dark' && !arrow ?
				<ButtonArrowDark onClick={() => handleClick()} disableRipple={true} sx={customStyle}>
          <p>{text} </p>
        </ButtonArrowDark> :
        <ButtonArrowDark onClick={() => handleClick()} disableRipple={true} sx={customStyle}>
          <p>{text} <Icon viewBox='0 0 18 24'/></p>
        </ButtonArrowDark>
      }
    </>
  )
}

export default NavButton;
